class Solution {
    public int strangePrinter(String s) {
        int n = s.length();
        int minTurns = n;
        for (int i = 1; i < n; i++) {
            int left = i;
            int right = n - 1;
            while (left >= 0 && right >= 0 && s.charAt(left) == s.charAt(right)) {
                minTurns--;
                if (left > right) {
                    swap(left, right);
                }
                left--;
                right--;
            }
        }
        return minTurns;
    }

    private void swap(int a, int b) {
        char temp = s.charAt(a);
        s.setCharAt(a, s.charAt(b));
        s.setCharAt(b, temp);
    }
}
